    "startFrame": 25984,
    "durationSec": 2.656,
    "durationFrames": 80,
    "speaker": "めたん",
    "text": "不安ビジネスって、本当に怖いですわ……。\r",
    "speakerColor": "#d6336c",
    "sceneId": 22,
    "sceneTitle": "なぜ人は脳トレを信じたいのか"
